namespace sv_cd9089823e0d4a44809953f9ae593b7d.Models;

public class WizardState
{
    // Step 1 – Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 – Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    /// <summary>Returns which steps the user has completed so far.</summary>
    public HashSet<int> CompletedSteps
    {
        get
        {
            var steps = new HashSet<int>();
            if (!string.IsNullOrWhiteSpace(FullName) && !string.IsNullOrWhiteSpace(Email))
                steps.Add(1);
            if (Jobs.Count > 0)
                steps.Add(2);
            if (References.Count > 0)
                steps.Add(3);
            return steps;
        }
    }
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_cd9089823e0d4a44809953f9ae593b7d.Models;

namespace sv_cd9089823e0d4a44809953f9ae593b7d.Services;

/// <summary>
/// Singleton state store keyed by a per-browser session ID.
/// Both the static layout (SSR) and interactive pages (SignalR circuit)
/// resolve the same session key from a cookie and access the same
/// <see cref="WizardState"/> instance, bridging the render-mode boundary.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardState> _store = new();

    public WizardState GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

@using sv_cd9089823e0d4a44809953f9ae593b7d.Models
@using sv_cd9089823e0d4a44809953f9ae593b7d.Services
@inherits LayoutComponentBase
@inject WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor

@* This layout renders statically (SSR). It reads the wizard state
   via the same singleton + session cookie that the interactive pages use. *@

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            <nav class="wizard-progress mb-4" aria-label="Application progress">
                <h6 class="text-muted mb-2">Step @CurrentStep of @TotalSteps</h6>
                <div class="d-flex gap-2 mb-3">
                    @for (int i = 0; i < TotalSteps; i++)
                    {
                        var step = Steps[i];
                        var stepNum = i + 1;
                        var isCurrent = stepNum == CurrentStep;
                        var isCompleted = _completedSteps.Contains(stepNum);

                        <a href="@step.Href"
                           class="wizard-step @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "")"
                           aria-current="@(isCurrent ? "step" : null)">
                            <span class="wizard-step-number">
                                @if (isCompleted && !isCurrent)
                                {
                                    <text>✓</text>
                                }
                                else
                                {
                                    @stepNum
                                }
                            </span>
                            <span class="wizard-step-label d-none d-md-inline">@step.Title</span>
                        </a>

                        @if (i < TotalSteps - 1)
                        {
                            <span class="wizard-step-connector"></span>
                        }
                    }
                </div>
            </nav>

            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private static readonly (string Href, string Title)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];

    private const int TotalSteps = 4;

    private int CurrentStep { get; set; } = 1;
    private HashSet<int> _completedSteps = [];

    protected override void OnInitialized()
    {
        var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
        CurrentStep = Array.FindIndex(Steps, s => path.StartsWith(s.Href, StringComparison.OrdinalIgnoreCase)) + 1;
        if (CurrentStep < 1) CurrentStep = 1;

        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            _completedSteps = StateService.GetOrCreate(sessionId).CompletedSteps;
        }
    }
}

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.top-row {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    justify-content: flex-end;
    height: 3.5rem;
    display: flex;
    align-items: center;
}

    .top-row ::deep a, .top-row ::deep .btn-link {
        white-space: nowrap;
        margin-left: 1.5rem;
        text-decoration: none;
    }

    .top-row ::deep a:hover, .top-row ::deep .btn-link:hover {
        text-decoration: underline;
    }

    .top-row ::deep a:first-child {
        overflow: hidden;
        text-overflow: ellipsis;
    }

@media (max-width: 640.98px) {
    .top-row {
        justify-content: space-between;
    }

    .top-row ::deep a, .top-row ::deep .btn-link {
        margin-left: 0;
    }
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .top-row {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .top-row, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
