namespace sv_cd9089823e0d4a44809953f9ae593b7d.Models;

public class WizardState
{
    // Step 1 – Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 – Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    /// <summary>Returns which steps the user has completed so far.</summary>
    public HashSet<int> CompletedSteps
    {
        get
        {
            var steps = new HashSet<int>();
            if (!string.IsNullOrWhiteSpace(FullName) && !string.IsNullOrWhiteSpace(Email))
                steps.Add(1);
            if (Jobs.Count > 0)
                steps.Add(2);
            if (References.Count > 0)
                steps.Add(3);
            return steps;
        }
    }
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_cd9089823e0d4a44809953f9ae593b7d.Models;

namespace sv_cd9089823e0d4a44809953f9ae593b7d.Services;

/// <summary>
/// Singleton state store keyed by a per-browser session ID.
/// Both the static layout (SSR) and interactive pages (SignalR circuit)
/// resolve the same session key from a cookie and access the same
/// <see cref="WizardState"/> instance, bridging the render-mode boundary.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardState> _store = new();

    public WizardState GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

@using sv_cd9089823e0d4a44809953f9ae593b7d.Models
@using sv_cd9089823e0d4a44809953f9ae593b7d.Services
