@code {
    private static readonly (string Href, string Title)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];

    private const int TotalSteps = 4;

    private int CurrentStep { get; set; } = 1;
    private HashSet<int> _completedSteps = [];

    protected override void OnInitialized()
    {
        var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
        CurrentStep = Array.FindIndex(Steps, s => path.StartsWith(s.Href, StringComparison.OrdinalIgnoreCase)) + 1;
        if (CurrentStep < 1) CurrentStep = 1;

        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            _completedSteps = StateService.GetOrCreate(sessionId).CompletedSteps;
        }
    }
}

