@page "/apply/personal-info"
@layout WizardLayout
@rendermode InteractiveServer

@using sv_cd9089823e0d4a44809953f9ae593b7d.Models
@using sv_cd9089823e0d4a44809953f9ae593b7d.Services

@inject WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Personal Info – Application</PageTitle>

<h1>Personal Information</h1>

<EditForm Model="_model" OnValidSubmit="HandleNext" FormName="personal-info">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText type="email" class="form-control" @bind-Value="_model.Email" />
    </div>

    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private WizardState _state = new();
    private PersonalInfoModel _model = new();

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            _state = StateService.GetOrCreate(sessionId);
            _model.FullName = _state.FullName;
            _model.Email = _state.Email;
        }
    }

    private void HandleNext()
    {
        _state.FullName = _model.FullName;
        _state.Email = _model.Email;
        Nav.NavigateTo("/apply/experience", forceLoad: true);
    }

    private sealed class PersonalInfoModel
    {
        [System.ComponentModel.DataAnnotations.Required]
        public string FullName { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required]
        [System.ComponentModel.DataAnnotations.EmailAddress]
        public string Email { get; set; } = "";
    }
}

@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@using sv_cd9089823e0d4a44809953f9ae593b7d.Models
@using sv_cd9089823e0d4a44809953f9ae593b7d.Services

@inject WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Experience – Application</PageTitle>

<h1>Work Experience</h1>

@if (_state.Jobs.Count == 0)
{
    <p class="text-muted">No job history entries yet. Add one below.</p>
}
else
{
    <div class="table-responsive mb-3">
        <table class="table table-sm table-striped">
            <thead>
                <tr><th>Company</th><th>Title</th><th>Years</th><th></th></tr>
            </thead>
            <tbody>
                @for (int i = 0; i < _state.Jobs.Count; i++)
                {
                    var idx = i;
                    var job = _state.Jobs[idx];
                    <tr>
                        <td>@job.Company</td>
                        <td>@job.Title</td>
                        <td>@job.Years</td>
                        <td><button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(idx)">✕</button></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

<fieldset class="border rounded p-3 mb-3">
    <legend class="w-auto px-2 fs-6">Add a job</legend>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Company" @bind="_newJob.Company" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Title" @bind="_newJob.Title" />
        </div>
        <div class="col-md-2">
            <input class="form-control" placeholder="Years" @bind="_newJob.Years" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-primary w-100" @onclick="AddJob">Add</button>
        </div>
    </div>
</fieldset>

<div class="d-flex justify-content-between">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">← Back</a>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private WizardState _state = new();
    private JobEntry _newJob = new();

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            _state = StateService.GetOrCreate(sessionId);
        }
    }

    private void AddJob()
    {
        if (string.IsNullOrWhiteSpace(_newJob.Company)) return;
        _state.Jobs.Add(_newJob);
        _newJob = new JobEntry();
    }

    private void RemoveJob(int index) => _state.Jobs.RemoveAt(index);

    private void HandleNext() => Nav.NavigateTo("/apply/references", forceLoad: true);
}

@page "/apply/references"
@layout WizardLayout
@rendermode InteractiveServer

@using sv_cd9089823e0d4a44809953f9ae593b7d.Models
@using sv_cd9089823e0d4a44809953f9ae593b7d.Services

@inject WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>References – Application</PageTitle>

<h1>References</h1>

@if (_state.References.Count == 0)
{
    <p class="text-muted">No references yet. Add one below.</p>
}
else
{
    <div class="table-responsive mb-3">
        <table class="table table-sm table-striped">
            <thead>
                <tr><th>Name</th><th>Relationship</th><th>Phone</th><th></th></tr>
            </thead>
            <tbody>
                @for (int i = 0; i < _state.References.Count; i++)
                {
                    var idx = i;
                    var r = _state.References[idx];
                    <tr>
                        <td>@r.Name</td>
                        <td>@r.Relationship</td>
                        <td>@r.Phone</td>
                        <td><button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(idx)">✕</button></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

<fieldset class="border rounded p-3 mb-3">
    <legend class="w-auto px-2 fs-6">Add a reference</legend>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Name" @bind="_newRef.Name" />
        </div>
        <div class="col-md-3">
            <input class="form-control" placeholder="Relationship" @bind="_newRef.Relationship" />
        </div>
        <div class="col-md-3">
            <input class="form-control" placeholder="Phone" @bind="_newRef.Phone" />
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-primary w-100" @onclick="AddRef">Add</button>
        </div>
    </div>
</fieldset>

<div class="d-flex justify-content-between">
    <a href="/apply/experience" class="btn btn-outline-secondary">← Back</a>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private WizardState _state = new();
    private ReferenceContact _newRef = new();

    protected override void OnInitialized()
    {
        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (!string.IsNullOrEmpty(sessionId))
        {
            _state = StateService.GetOrCreate(sessionId);
        }
    }

    private void AddRef()
    {
        if (string.IsNullOrWhiteSpace(_newRef.Name)) return;
        _state.References.Add(_newRef);
        _newRef = new ReferenceContact();
    }

    private void RemoveRef(int index) => _state.References.RemoveAt(index);

    private void HandleNext() => Nav.NavigateTo("/apply/review", forceLoad: true);
}

@page "/apply/review"
@layout WizardLayout
@rendermode InteractiveServer

@using sv_cd9089823e0d4a44809953f9ae593b7d.Models
@using sv_cd9089823e0d4a44809953f9ae593b7d.Services

@inject WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Review – Application</PageTitle>

<h1>Review Your Application</h1>

<div class="card mb-3">
    <div class="card-header"><strong>Step 1 – Personal Information</strong></div>
    <div class="card-body">
        @if (string.IsNullOrWhiteSpace(_state.FullName) && string.IsNullOrWhiteSpace(_state.Email))
        {
            <p class="text-muted mb-0">Not completed.</p>
        }
        else
        {
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@_state.FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@_state.Email</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Step 2 – Work Experience</strong></div>
    <div class="card-body">
        @if (_state.Jobs.Count == 0)
        {
            <p class="text-muted mb-0">No job entries.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead><tr><th>Company</th><th>Title</th><th>Years</th></tr></thead>
                <tbody>
                    @foreach (var job in _state.Jobs)
